1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent for scalar expressions.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	
6	#pragma once
7	
8	// AST node types
9	#define NODE_NUM    0   // integer literal (val = value)
10	#define NODE_BINOP  1   // binary op (val = operator tok type)
11	#define NODE_NEG    2   // monadic negate (right = operand)
12	
13	#define AST_MAX 64
14	
15	// AST storage (parallel arrays)
16	int node_type[AST_MAX];
17	int node_val[AST_MAX];
18	int node_left[AST_MAX];
19	int node_right[AST_MAX];
20	int node_count;
21	
22	// Parser state
23	int parse_pos;
24	int parse_err;
25	
26	// Allocate a new AST node
27	int ast_new() {
28	    if (node_count >= AST_MAX) {
29	        parse_err = 1;
30	        return 0;
31	    }
32	    int n = node_count;
33	    node_count++;
34	    node_left[n] = -1;
35	    node_right[n] = -1;
36	    return n;
37	}
38	
39	int ast_num(int val) {
40	    int n = ast_new();
41	    node_type[n] = NODE_NUM;
42	    node_val[n] = val;
43	    return n;
44	}
45	
46	int ast_binop(int op, int left, int right) {
47	    int n = ast_new();
48	    node_type[n] = NODE_BINOP;
49	    node_val[n] = op;
50	    node_left[n] = left;
51	    node_right[n] = right;
52	    return n;
53	}
54	
55	int ast_neg(int operand) {
56	    int n = ast_new();
57	    node_type[n] = NODE_NEG;
58	    node_right[n] = operand;
59	    return n;
60	}
61	
62	int is_binop(int ty) {
63	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH;
64	}
65	
66	// Combined parse function avoids mutual recursion.
67	// mode 0 = expression, mode 1 = value only
68	int parse_node(int mode);
69	
70	int parse_node(int mode) {
71	    if (parse_err) return 0;
72	
73	    int left;
74	    int ty = tok_type[parse_pos];
75	
76	    // -- Parse a value --
77	
78	    if (ty == TOK_NUM) {
79	        left = ast_num(tok_val[parse_pos]);
80	        parse_pos++;
81	    } else if (ty == TOK_LPAREN) {
82	        parse_pos++;
83	        left = parse_node(0);
84	        if (parse_err) return 0;
85	        if (tok_type[parse_pos] != TOK_RPAREN) {
86	            parse_err = 1;
87	            return 0;
88	        }
89	        parse_pos++;
90	    } else if (ty == TOK_MINUS) {
91	        // Monadic negate: applies to entire right expression (APL rule)
92	        parse_pos++;
93	        int operand = parse_node(0);
94	        if (parse_err) return 0;
95	        left = ast_neg(operand);
96	    } else {
97	        parse_err = 1;
98	        return 0;
99	    }
100	
101	    // -- If mode 0 (expr) and next is binop, parse right side --
102	
103	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
104	        int op = tok_type[parse_pos];
105	        parse_pos++;
106	        int right = parse_node(0);
107	        if (parse_err) return 0;
108	        return ast_binop(op, left, right);
109	    }
110	
111	    return left;
112	}
113	
114	// Parse the token stream. Returns root node index, or -1 on error.
115	int parse() {
116	    node_count = 0;
117	    parse_pos = 0;
118	    parse_err = 0;
119	
120	    int root = parse_node(0);
121	
122	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
123	        parse_err = 1;
